(
  sum by (site, storage_io_direction) (
    rate(storage_operation_time_seconds_total{host_name="$host_name", storage_type="storage_system"}[5m])
  ) / 
  clamp_min( # to make sure we don't divide by if no activity
    sum by (site, storage_io_direction) (
      rate(storage_operations_total{host_name="$host_name", storage_type="storage_system"}[5m])
    ), 
    0.0001
  )
)
and # Make sure there are some operations
(
  sum by (site, storage_io_direction) (
    rate(storage_operations_total{host_name="$host_name", storage_type="storage_system"}[5m])
  ) >= 1
)

